#include <iostream>
#include <vector>
#include <thread>
#include <mutex>
#include <atomic>

struct Account {
    std::string id;
    double balance;

    Account(const std::string& id, double balance) : id(id), balance(balance) {}
};

class BankSystem {
public:
    void addAccount(const Account& account) {
        std::lock_guard<std::mutex> lock(mutex_);
        accounts_[account.id] = account.balance;
    }

    void deposit(const std::string& id, double amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(id) != accounts_.end()) {
            accounts_[id] += amount;
        }
    }

    void withdraw(const std::string& id, double amount) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(id) != accounts_.end() && accounts_[id] >= amount) {
            accounts_[id] -= amount;
        }
    }

    double getBalance(const std::string& id) const {
        std::lock_guard<std::mutex> lock(mutex_);
        if (accounts_.find(id) != accounts_.end()) {
            return accounts_.at(id);
        }
        return 0.0;
    }

private:
    std::mutex mutex_;
    std::unordered_map<std::string, double> accounts_;
};

void processTransaction(BankSystem& bank, const std::string& id, int type, double amount) {
    if (type == 1) {
        bank.deposit(id, amount);
    } else if (type == 2) {
        bank.withdraw(id, amount);
    }
}

int main() {
    BankSystem bank;
    bank.addAccount(Account("A001", 1000.0));
    bank.addAccount(Account("A002", 500.0));

    std::vector<std::thread> threads;

    for (int i = 0; i < 10; ++i) {
        threads.emplace_back(processTransaction, std::ref(bank), "A001", 1, 100.0);
        threads.emplace_back(processTransaction, std::ref(bank), "A002", 2, 50.0);
    }

    for (auto& thread : threads) {
        thread.join();
    }

    std::cout << "Balance A001: " << bank.getBalance("A001") << std::endl;
    std::cout << "Balance A002: " << bank.getBalance("A002") << std::endl;

    return 0;
}